import{_ as t,o as e,c as i,ak as s}from"./chunks/framework.d_5_XLDx.js";const n=JSON.parse('{"title":"AList 项目所有权疑似更迭：开源网盘工具引发社区关注","description":"","frontmatter":{"title":"AList 项目所有权疑似更迭：开源网盘工具引发社区关注","createTime":"2025/06/11 03:13:39","permalink":"/article/dsbch7va/","tags":["AList","网盘管理","开源工具","社区动态","安全风险","GitHub","Docker","Telegram","腾讯云 COS"]},"headers":[],"relativePath":"blog/ermao/新闻/网盘管理工具alist疑似被出售.md","filePath":"blog/ermao/新闻/网盘管理工具alist疑似被出售.md","lastUpdated":1769775157000}'),l={name:"blog/ermao/新闻/网盘管理工具alist疑似被出售.md"};function r(m,a,p,g,o,c){return e(),i("div",null,[...a[0]||(a[0]=[s('<p>近日，广受欢迎的开源网盘管理工具 AList 疑似发生所有权变更，引发社区广泛讨论和担忧。多个迹象表明项目可能已被转手，用户需警惕潜在风险。</p><h2 id="异常迹象汇总" tabindex="-1">异常迹象汇总 <a class="header-anchor" href="#异常迹象汇总" aria-label="Permalink to &quot;异常迹象汇总&quot;">​</a></h2><p>社区成员发现了多项可疑变化：</p><ol><li>官方文档中的下载链接被悄然修改</li><li>最新版 Docker 镜像内容出现变动</li><li>开发者难以联系，官方 Telegram 群组管理权变更</li><li>GitHub 仓库有多次可疑修改记录，包含广告相关内容</li></ol><p><img src="https://image.ermao.net/images/article/dsbch7va/image.png" alt="Alist开源项目被出售"></p><h2 id="github-仓库异常活动" tabindex="-1">GitHub 仓库异常活动 <a class="header-anchor" href="#github-仓库异常活动" aria-label="Permalink to &quot;GitHub 仓库异常活动&quot;">​</a></h2><p>GitHub 仓库 (<a href="http://github.com/alist-org/alist" target="_blank" rel="noreferrer">http://github.com/alist-org/alist</a>) 上可见多处可疑变更，部分提交记录明确包含广告相关内容：</p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-1.png" alt="Alist开源项目被出售"></p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-2.png" alt="Alist开源项目被出售"></p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-3.png" alt="Alist开源项目被出售"></p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-4.png" alt="Alist开源项目被出售"></p><h2 id="alist-桌面版应用疑似被商业化" tabindex="-1">Alist 桌面版应用疑似被商业化 <a class="header-anchor" href="#alist-桌面版应用疑似被商业化" aria-label="Permalink to &quot;Alist 桌面版应用疑似被商业化&quot;">​</a></h2><p>除核心项目外，AList 桌面版程序也出现了被打包销售的情况：</p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-5.png" alt="Alist开源项目被出售"></p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-6.png" alt="Alist开源项目被出售"></p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-7.png" alt="Alist开源项目被出售"></p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-8.png" alt="Alist开源项目被出售"></p><p><img src="https://image.ermao.net/images/article/dsbch7va/image-9.png" alt="Alist开源项目被出售"></p><h2 id="社区最新进展" tabindex="-1">社区最新进展 <a class="header-anchor" href="#社区最新进展" aria-label="Permalink to &quot;社区最新进展&quot;">​</a></h2><p>Telegram 群组最新消息显示：</p><ul><li>AList 所有权疑似已经变动，建议用户注意代码安全风险</li><li>中文文档中新增了微信链接等非技术内容</li><li>官网与下载地址已被更换</li><li>新更新的腾讯云 COS 链接因&quot;文件非法&quot;被腾讯云封禁</li></ul><p>用户可考虑关注其他类似工具，如开源 CDN 程序 GOedge 等，以防 AList 项目后续发展不确定性。</p><p>社区将持续关注此事件进展，建议用户在情况明朗前谨慎使用 AList 最新版本。</p><h3 id="alist新作者最新回应" tabindex="-1">Alist新作者最新回应 <a class="header-anchor" href="#alist新作者最新回应" aria-label="Permalink to &quot;Alist新作者最新回应&quot;">​</a></h3><p><img src="https://image.ermao.net/images/article/dsbch7va/image-10.png" alt="Alist开源项目被出售"></p><p>附连接地址: <a href="https://github.com/AlistGo/alist/issues/8649" target="_blank" rel="noreferrer">项目是被卖了吗？官网已经 404 了，隔壁 docs 的文档被大改持续两个星期</a></p>',26)])])}const d=t(l,[["render",r]]);export{n as __pageData,d as default};
